INSERT INTO tb_books (id, title, author, description, publisher, published_date, isbn, category, review_cnt, rating, is_deleted, created_at, updated_at) VALUES
('b0000000-0000-0000-0000-000000000001', '채식주의자',           '한강',         '세 편의 연작 소설로 이루어진 작품으로, 평범한 여성 영혜가 어느 날 채식주의자가 되기로 결심하면서 벌어지는 이야기.',                   '창비',       '2007-10-30', '9788936434595', 'NOVEL',               5, 4.6, false, NOW(), NOW()),
('b0000000-0000-0000-0000-000000000002', '소년이 온다',           '한강',         '1980년 5월 광주를 배경으로 한 소설. 계엄군에 의해 희생된 이들의 이야기를 다룬다.',                                           '창비',       '2014-05-19', '9788936434038', 'NOVEL',               4, 4.8, false, NOW(), NOW()),
('b0000000-0000-0000-0000-000000000003', '82년생 김지영',         '조남주',       '1982년에 태어난 평범한 한국 여성 김지영의 삶을 통해 한국 사회의 성차별 구조를 드러낸 소설.',                                    '민음사',      '2016-10-14', '9788937473388', 'NOVEL',               4, 4.3, false, NOW(), NOW()),
('b0000000-0000-0000-0000-000000000004', '사피엔스',             '유발 하라리',   '인류의 역사를 새로운 시각으로 조명하는 책. 호모 사피엔스가 어떻게 지구를 지배하게 되었는지 탐구한다.',                              '김영사',      '2015-11-24', '9788934972464', 'HISTORY_CULTURE',     3, 4.5, false, NOW(), NOW()),
('b0000000-0000-0000-0000-000000000005', '총, 균, 쇠',           '재레드 다이아몬드', '왜 어떤 문명은 번성하고 어떤 문명은 쇠퇴했는지를 지리, 생물학, 역사학적 관점으로 분석한 명저.',                             '문학사상',    '2005-12-19', '9788970128177', 'HISTORY_CULTURE',     3, 4.7, false, NOW(), NOW()),
('b0000000-0000-0000-0000-000000000006', '코스모스',             '칼 세이건',     '우주의 역사와 과학적 탐구 정신을 대중적으로 풀어낸 과학 교양서의 고전.',                                                      '사이언스북스', '2006-12-20', '9788983712509', 'SCIENCE',             3, 4.9, false, NOW(), NOW()),
('b0000000-0000-0000-0000-000000000007', '클린 코드',            '로버트 C. 마틴','읽기 좋고 유지보수하기 쉬운 코드를 작성하는 방법에 대한 소프트웨어 개발 필독서.',                                              '인사이트',    '2013-12-24', '9788966260959', 'COMPUTER_IT',         3, 4.4, false, NOW(), NOW()),
('b0000000-0000-0000-0000-000000000008', '미움받을 용기',         '기시미 이치로', '아들러 심리학을 바탕으로 자유롭고 행복하게 사는 방법을 대화 형식으로 풀어낸 자기계발서.',                                         '인플루엔셜',  '2014-11-17', '9788996991342', 'SELF_DEVELOPMENT',    3, 4.2, false, NOW(), NOW()),
('b0000000-0000-0000-0000-000000000009', '돈의 심리학',           '모건 하우절',   '돈을 잘 다루는 것은 지식이 아니라 행동의 문제임을 설득력 있게 설명하는 금융 심리 에세이.',                                       '인플루엔셜',  '2021-10-20', '9791191056075', 'ECONOMY_BUSINESS',    2, 4.5, false, NOW(), NOW()),
('b0000000-0000-0000-0000-000000000010', '어린 왕자',            '앙투안 드 생텍쥐페리', '사막에 불시착한 조종사와 어린 왕자의 만남을 통해 인간의 본질을 탐구하는 세계적인 고전 소설.',                           '열린책들',    '2015-06-01', '9788932917245', 'NOVEL',               1, 4.0, false, NOW(), NOW());


