INSERT INTO tb_reviews (id, book_id, user_id, content, rating, like_cnt, comment_cnt, is_deleted, created_at, updated_at) VALUES
-- 채식주의자 (book 1) - 5개
('e0000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000001', '한강 작가의 문체가 너무 아름답습니다. 채식이라는 행위에 담긴 상징성이 인상적이었어요.',              5, 3, 2, false, NOW() - INTERVAL '10 days', NOW()),
('e0000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000002', '불편하지만 눈을 뗄 수 없는 소설. 한국 문학의 저력을 느꼈습니다.',                                    5, 2, 1, false, NOW() - INTERVAL '9 days',  NOW()),
('e0000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000003', '세 편의 연작이 유기적으로 연결되는 방식이 탁월해요. 여러 번 읽어도 새로운 발견이 있습니다.',              4, 1, 0, false, NOW() - INTERVAL '8 days',  NOW()),
('e0000000-0000-0000-0000-000000000004', 'b0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000004', '노벨문학상 수상 이후 다시 읽었는데 더 깊이 느껴지네요.',                                              4, 0, 0, false, NOW() - INTERVAL '7 days',  NOW()),
('e0000000-0000-0000-0000-000000000005', 'b0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000005', '처음엔 낯설었지만 읽다 보면 빠져드는 매력이 있어요. 강추합니다.',                                     5, 1, 1, false, NOW() - INTERVAL '6 days',  NOW()),

-- 소년이 온다 (book 2) - 4개
('e0000000-0000-0000-0000-000000000006', 'b0000000-0000-0000-0000-000000000002', 'd0000000-0000-0000-0000-000000000001', '읽는 내내 눈물이 멈추지 않았습니다. 역사를 잊지 않겠다는 다짐을 하게 된 책.',                          5, 5, 3, false, NOW() - INTERVAL '15 days', NOW()),
('e0000000-0000-0000-0000-000000000007', 'b0000000-0000-0000-0000-000000000002', 'd0000000-0000-0000-0000-000000000002', '5·18을 이렇게 문학적으로 승화시킬 수 있다는 것에 경이로움을 느꼈습니다.',                               5, 4, 2, false, NOW() - INTERVAL '14 days', NOW()),
('e0000000-0000-0000-0000-000000000008', 'b0000000-0000-0000-0000-000000000002', 'd0000000-0000-0000-0000-000000000003', '2인칭 시점이 독자를 직접 역사 속으로 끌어당기는 느낌. 정말 대단한 작품입니다.',                         5, 3, 1, false, NOW() - INTERVAL '13 days', NOW()),
('e0000000-0000-0000-0000-000000000009', 'b0000000-0000-0000-0000-000000000002', 'd0000000-0000-0000-0000-000000000004', '무겁고 힘들지만 반드시 읽어야 할 책. 모두에게 권합니다.',                                             4, 2, 0, false, NOW() - INTERVAL '12 days', NOW()),

-- 82년생 김지영 (book 3) - 4개
('e0000000-0000-0000-0000-000000000010', 'b0000000-0000-0000-0000-000000000003', 'd0000000-0000-0000-0000-000000000001', '통계와 실화를 기반으로 해서 더 현실적으로 다가왔어요. 많은 생각을 하게 만드는 책.',                      4, 4, 2, false, NOW() - INTERVAL '20 days', NOW()),
('e0000000-0000-0000-0000-000000000011', 'b0000000-0000-0000-0000-000000000003', 'd0000000-0000-0000-0000-000000000003', '공감되는 부분이 너무 많아서 읽는 내내 답답했지만 필요한 이야기라고 생각합니다.',                         5, 3, 1, false, NOW() - INTERVAL '19 days', NOW()),
('e0000000-0000-0000-0000-000000000012', 'b0000000-0000-0000-0000-000000000003', 'd0000000-0000-0000-0000-000000000005', '짧지만 강렬한 울림이 있는 소설. 성별에 관계없이 읽어봤으면 하는 책입니다.',                              4, 2, 0, false, NOW() - INTERVAL '18 days', NOW()),
('e0000000-0000-0000-0000-000000000013', 'b0000000-0000-0000-0000-000000000003', 'd0000000-0000-0000-0000-000000000006', '사회구조적인 문제를 개인의 이야기로 잘 녹여냈어요.',                                                  4, 1, 0, false, NOW() - INTERVAL '17 days', NOW()),

-- 사피엔스 (book 4) - 3개
('e0000000-0000-0000-0000-000000000014', 'b0000000-0000-0000-0000-000000000004', 'd0000000-0000-0000-0000-000000000002', '인류 역사를 이렇게 쉽고 흥미롭게 설명할 수 있다는 게 놀랍습니다. 필독서!',                              5, 3, 2, false, NOW() - INTERVAL '25 days', NOW()),
('e0000000-0000-0000-0000-000000000015', 'b0000000-0000-0000-0000-000000000004', 'd0000000-0000-0000-0000-000000000004', '세계관이 넓어지는 느낌. 허구의 힘이라는 개념이 특히 인상적이었어요.',                                   4, 2, 1, false, NOW() - INTERVAL '24 days', NOW()),
('e0000000-0000-0000-0000-000000000016', 'b0000000-0000-0000-0000-000000000004', 'd0000000-0000-0000-0000-000000000005', '다소 주관적인 해석도 있지만 전체적으로 매우 유익한 책입니다.',                                         4, 1, 0, false, NOW() - INTERVAL '23 days', NOW()),

-- 총, 균, 쇠 (book 5) - 3개
('e0000000-0000-0000-0000-000000000017', 'b0000000-0000-0000-0000-000000000005', 'd0000000-0000-0000-0000-000000000001', '두껍지만 읽는 내내 흥미진진합니다. 지리결정론적 시각이 신선했어요.',                                    5, 4, 2, false, NOW() - INTERVAL '30 days', NOW()),
('e0000000-0000-0000-0000-000000000018', 'b0000000-0000-0000-0000-000000000005', 'd0000000-0000-0000-0000-000000000003', '문명의 불평등이 왜 생겨났는지 명쾌하게 설명해줍니다. 강력 추천!',                                       5, 3, 1, false, NOW() - INTERVAL '29 days', NOW()),
('e0000000-0000-0000-0000-000000000019', 'b0000000-0000-0000-0000-000000000005', 'd0000000-0000-0000-0000-000000000006', '퓰리처상 수상작답게 방대한 내용을 체계적으로 정리했습니다.',                                            4, 2, 0, false, NOW() - INTERVAL '28 days', NOW()),

-- 코스모스 (book 6) - 3개
('e0000000-0000-0000-0000-000000000020', 'b0000000-0000-0000-0000-000000000006', 'd0000000-0000-0000-0000-000000000002', '칼 세이건의 문장은 그 자체로 시입니다. 우주에 대한 경외감이 생겨나요.',                                  5, 6, 3, false, NOW() - INTERVAL '35 days', NOW()),
('e0000000-0000-0000-0000-000000000021', 'b0000000-0000-0000-0000-000000000006', 'd0000000-0000-0000-0000-000000000004', '과학책이지만 철학적이고 시적인 내용이 가득합니다. 평생 간직할 책.',                                     5, 5, 2, false, NOW() - INTERVAL '34 days', NOW()),
('e0000000-0000-0000-0000-000000000022', 'b0000000-0000-0000-0000-000000000006', 'd0000000-0000-0000-0000-000000000007', '처음 읽어보는 천문학 교양서였는데 전혀 어렵지 않았어요. 입문서로 최고.',                                  5, 4, 1, false, NOW() - INTERVAL '33 days', NOW()),

-- 클린 코드 (book 7) - 3개
('e0000000-0000-0000-0000-000000000023', 'b0000000-0000-0000-0000-000000000007', 'd0000000-0000-0000-0000-000000000001', '개발자라면 꼭 읽어야 할 책. 코드리뷰 기준이 생겼습니다.',                                              5, 3, 2, false, NOW() - INTERVAL '40 days', NOW()),
('e0000000-0000-0000-0000-000000000024', 'b0000000-0000-0000-0000-000000000007', 'd0000000-0000-0000-0000-000000000005', '당장 내 코드를 다 리팩토링하고 싶어졌습니다. 실무에 바로 적용 가능해요.',                                4, 2, 1, false, NOW() - INTERVAL '39 days', NOW()),
('e0000000-0000-0000-0000-000000000025', 'b0000000-0000-0000-0000-000000000007', 'd0000000-0000-0000-0000-000000000006', '예시 코드가 Java 중심이지만 원칙은 모든 언어에 적용됩니다.',                                            4, 1, 0, false, NOW() - INTERVAL '38 days', NOW()),

-- 미움받을 용기 (book 8) - 3개
('e0000000-0000-0000-0000-000000000026', 'b0000000-0000-0000-0000-000000000008', 'd0000000-0000-0000-0000-000000000002', '대화 형식이라 쉽게 읽힙니다. 아들러 심리학의 핵심을 잘 전달해요.',                                      4, 2, 1, false, NOW() - INTERVAL '45 days', NOW()),
('e0000000-0000-0000-0000-000000000027', 'b0000000-0000-0000-0000-000000000008', 'd0000000-0000-0000-0000-000000000003', '인간관계로 힘들 때 읽으면 많은 위로가 됩니다. 두고두고 읽을 책.',                                       4, 1, 0, false, NOW() - INTERVAL '44 days', NOW()),
('e0000000-0000-0000-0000-000000000028', 'b0000000-0000-0000-0000-000000000008', 'd0000000-0000-0000-0000-000000000007', '처음엔 공감 못했는데 다 읽고 나니 생각이 많이 바뀌었어요.',                                             4, 0, 0, false, NOW() - INTERVAL '43 days', NOW()),

-- 돈의 심리학 (book 9) - 2개
('e0000000-0000-0000-0000-000000000029', 'b0000000-0000-0000-0000-000000000009', 'd0000000-0000-0000-0000-000000000004', '돈에 대한 관점을 바꿔준 책. 투자 마인드셋에 대해 다시 생각하게 됐어요.',                                 5, 3, 2, false, NOW() - INTERVAL '5 days',  NOW()),
('e0000000-0000-0000-0000-000000000030', 'b0000000-0000-0000-0000-000000000009', 'd0000000-0000-0000-0000-000000000007', '숫자와 공식 없이 심리학으로 돈을 설명하는 신선한 접근. 추천합니다.',                                     4, 2, 1, false, NOW() - INTERVAL '4 days',  NOW()),

-- 어린 왕자 (book 10) - 1개
('e0000000-0000-0000-0000-000000000031', 'b0000000-0000-0000-0000-000000000010', 'd0000000-0000-0000-0000-000000000003', '어른이 된 후 다시 읽으니 어릴 때와 다른 감동이 밀려옵니다. 영원한 고전.',                               4, 1, 0, false, NOW() - INTERVAL '3 days',  NOW());


