-- 채식주의자 리뷰 댓글
('c0000000-0000-0000-0000-000000000001', 'e0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000002', '저도 같은 생각이에요! 한강 작가의 문체는 정말 독보적이죠.',                false, NOW() - INTERVAL '9 days',  NOW()),
('c0000000-0000-0000-0000-000000000002', 'e0000000-0000-0000-0000-000000000001', 'd0000000-0000-0000-0000-000000000003', '채식이 가지는 상징성 정말 인상적이었어요. 공감합니다.',                   false, NOW() - INTERVAL '8 days',  NOW()),
('c0000000-0000-0000-0000-000000000003', 'e0000000-0000-0000-0000-000000000002', 'd0000000-0000-0000-0000-000000000001', '맞아요, 불편한데 계속 읽게 되는 묘한 매력이 있죠.',                       false, NOW() - INTERVAL '8 days',  NOW()),
('c0000000-0000-0000-0000-000000000004', 'e0000000-0000-0000-0000-000000000005', 'd0000000-0000-0000-0000-000000000004', '저도 처음엔 낯설었는데 결국 최애 책이 됐어요!',                           false, NOW() - INTERVAL '5 days',  NOW()),

-- 소년이 온다 리뷰 댓글
('c0000000-0000-0000-0000-000000000005', 'e0000000-0000-0000-0000-000000000006', 'd0000000-0000-0000-0000-000000000002', '저도 내내 울었어요. 정말 잊어서는 안 될 역사입니다.',                      false, NOW() - INTERVAL '14 days', NOW()),
('c0000000-0000-0000-0000-000000000006', 'e0000000-0000-0000-0000-000000000006', 'd0000000-0000-0000-0000-000000000005', '반드시 읽어야 할 책이에요. 역사를 기억해야 하니까요.',                      false, NOW() - INTERVAL '13 days', NOW()),
('c0000000-0000-0000-0000-000000000007', 'e0000000-0000-0000-0000-000000000006', 'd0000000-0000-0000-0000-000000000006', '노벨상이 이렇게 기쁜 건 처음이에요. 세상이 이 작품을 알게 됐으니.',         false, NOW() - INTERVAL '12 days', NOW()),
('c0000000-0000-0000-0000-000000000008', 'e0000000-0000-0000-0000-000000000007', 'd0000000-0000-0000-0000-000000000003', '2인칭 시점이 그렇게 강렬할 수 있다는 게 정말 놀랍죠.',                     false, NOW() - INTERVAL '13 days', NOW()),
('c0000000-0000-0000-0000-000000000009', 'e0000000-0000-0000-0000-000000000008', 'd0000000-0000-0000-0000-000000000001', '완전 공감해요. 2인칭 서술이 독자를 사건 속으로 끌어당기더라고요.',           false, NOW() - INTERVAL '12 days', NOW()),

